import type { HTMLAttributes } from 'react';
import type { TestComponentProps } from 'src/types/test-component';
/**
 * Доступные значения spacing на основе токенов размеров.
 */
export type BoxSpacing = 'none' | 'x1' | 'x2' | 'x3' | 'x4' | 'x5' | 'x6' | 'x7' | 'x8' | 'x9' | 'x10';
/**
 * Поддерживаемые `display` значения.
 */
export type BoxDisplay = 'block' | 'inline' | 'inline-block' | 'flex' | 'inline-flex' | 'grid' | 'inline-grid';
/**
 * Layout-пропсы, доступные для `Box`.
 */
export interface BoxOwnProps {
    /**
     * Семантический HTML‑тег, используемый для рендера контейнера.
     * По умолчанию `div`. Поддерживаются только HTML‑теги (не SVG).
     */
    as?: keyof HTMLElementTagNameMap;
    /**
     * CSS значение display, по умолчанию `block`.
     */
    display?: BoxDisplay;
    /**
     * Полный padding по токенам spacing.
     */
    padding?: BoxSpacing;
    /**
     * Горизонтальные паддинги (left/right).
     */
    paddingX?: BoxSpacing;
    /**
     * Вертикальные паддинги (top/bottom).
     */
    paddingY?: BoxSpacing;
    /**
     * Полный margin по токенам spacing.
     */
    margin?: BoxSpacing;
    /**
     * Горизонтальные маргины (left/right).
     */
    marginX?: BoxSpacing;
    /**
     * Вертикальные маргины (top/bottom).
     */
    marginY?: BoxSpacing;
    /**
     * Притягивает контейнер на всю ширину родителя.
     */
    fullWidth?: boolean;
    /**
     * Пользовательский класс.
     */
    className?: string;
}
/**
 * Публичные пропсы `Box`.
 */
export type BoxProps = BoxOwnProps & HTMLAttributes<HTMLDivElement> & TestComponentProps;
